1	// game-of-life.spec.ts
2	import { describe, it, expect } from "vitest";
3	import { nextGeneration } from "./game-of-life.js";
4	
5	describe("Conway's Game of Life", () => {
6	  it("should return an empty set when no cells are alive", () => {
7	    expect(nextGeneration(new Set())).toEqual(new Set());
8	  });
9	  it("should kill a single living cell with no neighbors (underpopulation)", () => {
10	    expect(nextGeneration(new Set(["0,0"]))).toEqual(new Set());
11	  });
12	  it("should kill a living cell with only one neighbor (underpopulation)", () => {
13	    expect(nextGeneration(new Set(["0,0", "1,0"]))).toEqual(new Set());
14	  });
15	  it("should keep a living cell alive when it has two live neighbors", () => {
16	    expect(nextGeneration(new Set(["0,0", "1,0", "2,0"]))).toEqual(new Set(["1,0", "1,1", "1,-1"]));
17	  });
18	  it.todo("should keep a living cell alive when it has three live neighbors");
19	  it.todo("should kill a living cell with more than three live neighbors (overpopulation)");
20	  it.todo("should bring a dead cell to life when it has exactly three live neighbors (reproduction)");
21	  it.todo("should handle cells with negative coordinates");
22	});
23

1	export const nextGeneration = (cells: Set<string>): Set<string> => {
2	  const neighborCounts = countLiveNeighbors(cells);
3	  const result = new Set<string>();
4	  for (const [key, count] of neighborCounts) {
5	    if (cellLivesNextGeneration(count, cells.has(key))) {
6	      result.add(key);
7	    }
8	  }
9	  return result;
10	};
11	
12	const countLiveNeighbors = (cells: Set<string>): Map<string, number> => {
13	  const neighborCounts = new Map<string, number>();
14	  for (const cell of cells) {
15	    const [xStr, yStr] = cell.split(",");
16	    const x = Number(xStr);
17	    const y = Number(yStr);
18	    for (let dx = -1; dx <= 1; dx++) {
19	      for (let dy = -1; dy <= 1; dy++) {
20	        if (dx === 0 && dy === 0) continue;
21	        const key = `${x + dx},${y + dy}`;
22	        neighborCounts.set(key, (neighborCounts.get(key) ?? 0) + 1);
23	      }
24	    }
25	  }
26	  return neighborCounts;
27	};
28	
29	const cellLivesNextGeneration = (liveNeighborCount: number, isAlive: boolean): boolean =>
30	  liveNeighborCount === 3 || (liveNeighborCount === 2 && isAlive);
